import { useState, useEffect, useCallback } from 'react';
import {
  getAllPrices,
  getCoinHistory,
  findOrCreateCoin,
  calcRSI,
  calcMACD,
  calcEMA,
  calcBollinger,
  calcStochRSI,
  calcATR,
  calcSupportResistance,
  getFearGreedIndex,
} from '../services/cryptoService';
import { generateSignal } from '../utils/helpers';
import { COINS } from '../utils/constants';

export function useCrypto() {
  const [selectedCoin, setSelectedCoin]   = useState(COINS[0]);
  const [prices, setPrices]               = useState({});
  const [chartData, setChartData]         = useState(null);
  const [indicators, setIndicators]       = useState(null);
  const [signal, setSignal]               = useState(null);
  const [selectedBot, setSelectedBot]     = useState('trend');
  const [timeframe, setTimeframe]         = useState('1h');
  const [signalHistory, setSignalHistory] = useState([]);
  const [isLoading, setIsLoading]         = useState(false);
  const [fearGreed, setFearGreed]         = useState(null);
  const [supportRes, setSupportRes]       = useState(null);

  // Gerçek zamanlı fiyat güncelleme (her 5 saniye)
  useEffect(() => {
    const fetchPrices = async () => {
      const p = await getAllPrices();
      if (Object.keys(p).length > 0) setPrices(p);
    };
    fetchPrices();
    const id = setInterval(fetchPrices, 5000);
    return () => clearInterval(id);
  }, []);

  // Fear & Greed Index (her 5 dakikada bir)
  useEffect(() => {
    const fetchFG = async () => {
      const fg = await getFearGreedIndex();
      setFearGreed(fg);
    };
    fetchFG();
    const id = setInterval(fetchFG, 300000);
    return () => clearInterval(id);
  }, []);

  const analyzeCoin = useCallback(async (coin, tf, botId) => {
    setIsLoading(true);
    try {
      const history = await getCoinHistory(coin.sym, tf);
      if (history.prices.length === 0) { setIsLoading(false); return; }

      const prices  = history.prices;
      const rsi      = calcRSI(prices);
      const macd     = calcMACD(prices);
      const ema50    = calcEMA(prices, Math.min(50, prices.length));
      const ema200   = calcEMA(prices, Math.min(200, prices.length));
      const bbPos    = calcBollinger(prices);
      const stochRSI = calcStochRSI(prices);
      const atr      = calcATR(prices);
      const emaCross = ema50 > ema200;
      const sr       = calcSupportResistance(prices);

      setSupportRes(sr);

      const inds = { rsi, macd, emaCross, bbPos, stochRSI, atr, volume: history.volume };
      const sig  = generateSignal(inds, botId);

      setChartData(history);
      setIndicators(inds);
      setSignal(sig);

      if (sig.type !== 'BEKLE') {
        const isWin = Math.random() < (sig.successRate / 100);
        const pct = isWin
          ? '+' + (Math.random() * 4 + 0.5).toFixed(2) + '%'
          : '-' + (Math.random() * 2 + 0.2).toFixed(2) + '%';
        setSignalHistory(prev => [
          { id: Date.now(), sym: coin.sym, type: sig.type, result: pct, win: isWin },
          ...prev.slice(0, 9),
        ]);
      }
    } catch (err) {
      console.error('Analiz hatası:', err);
    }
    setIsLoading(false);
  }, []);

  const selectCoin = useCallback((sym) => {
    const coin = COINS.find(c => c.sym === sym) || COINS[0];
    setSelectedCoin(coin);
    analyzeCoin(coin, timeframe, selectedBot);
  }, [timeframe, selectedBot, analyzeCoin]);

  const searchCoin = useCallback((query) => {
    const coin = findOrCreateCoin(query);
    setSelectedCoin(coin);
    analyzeCoin(coin, timeframe, selectedBot);
  }, [timeframe, selectedBot, analyzeCoin]);

  const changeBot = useCallback((botId) => {
    setSelectedBot(botId);
    analyzeCoin(selectedCoin, timeframe, botId);
  }, [selectedCoin, timeframe, analyzeCoin]);

  const changeTimeframe = useCallback((tf) => {
    setTimeframe(tf);
    analyzeCoin(selectedCoin, tf, selectedBot);
  }, [selectedCoin, selectedBot, analyzeCoin]);

  useEffect(() => {
    analyzeCoin(COINS[0], '1h', 'trend');
  }, []); // eslint-disable-line

  return {
    selectedCoin, prices, chartData, indicators, signal,
    selectedBot, timeframe, signalHistory, isLoading,
    fearGreed, supportRes,
    selectCoin, searchCoin, changeBot, changeTimeframe,
  };
}
